import sailpoint.object.Identity;

    String stepA = "Intialize leaverDate";
    String stepB = "Set Pending leaverDate";
    String stepC = "Set Exclusion leaverDate";

    if (step.getName().equalsIgnoreCase(stepA)) {
        
        Identity refIdentity = context.getObjectByName(Identity.class, identityName);
        
        if (refIdentity != null) {
        
        refIdentity.setAttribute("leaverDate","19000101");
        
        context.saveObject(refIdentity);
        context.commitTransaction();

        }

    }   

    if (step.getName().equalsIgnoreCase(stepB)) {
        
