        if (refIdentity != null) {
        
        refIdentity.setAttribute("leaverDate","19000102");
        
        context.saveObject(refIdentity);
        context.commitTransaction();

        }

    }   

    if (step.getName().equalsIgnoreCase(stepC)) {
        
